template <typename scalar_t>
__launch_bounds__(256, 8)
__global__ void fused_neuralgrok_amplifier_moe_kernel(
    const scalar_t* __restrict__ grad,
    scalar_t* __restrict__ amplified_grad,
    const bool* __restrict__ active_mask,
    const float* __restrict__ W1,
    const float* __restrict__ b1,
    const float* __restrict__ W2,
    const float* __restrict__ b2,
    const float alpha,
    const float beta,
    const int N,
    const int H
) {
    extern __shared__ char smem_raw[];
    float* smem = reinterpret_cast<float*>(smem_raw);
    float* sW1 = smem;
    float* sb1 = sW1 + H;
    float* sW2 = sb1 + H;
    float* sb2 = sW2 + H;

    const int tid = threadIdx.x;

    for (int i = tid; i < H; i += blockDim.x)
        sW1[i] = W1[i];
    for (int i = tid; i < H; i += blockDim.x)
        sb1[i] = b1[i];
    for (int i = tid; i < H; i += blockDim.x)
        sW2[i] = W2[i];
    if (tid == 0)
        sb2[0] = b2[0];
    __syncthreads();

    const int idx = blockIdx.x * blockDim.x + tid;
    if (idx >= N) return;
    if (!active_mask[idx]) return;

    const float g = static_cast<float>(grad[idx]);

    float mlp_out = 0.0f;
    for (int h = 0; h < H; h++) {
        float z = sW1[h] * g + sb1[h];
        z = (z > 0.0f) ? z : 0.0f;
        mlp_out += sW2[h] * z;
    }
    mlp_out += sb2[0];

    const float amp = g * (alpha * mlp_out + beta);
    amplified_grad[idx] = static_cast<scalar_t>(amp);
}

