    auto W2_f = W2.dtype() == torch::kFloat32 ? W2.contiguous() : W2.to(torch::kFloat32).contiguous();
    auto b2_f = b2.dtype() == torch::kFloat32 ? b2.contiguous() : b2.to(torch::kFloat32).contiguous();

    AT_DISPATCH_FLOATING_TYPES_AND2(
        at::ScalarType::Half, at::ScalarType::BFloat16,
        grad.scalar_type(), "fused_sg11_mu_metanet_moe", ([&] {
        fused_sg11_mu_metanet_moe_kernel<scalar_t><<<grid, BLOCK_SIZE, smem_bytes>>>(
            mu.data_ptr<scalar_t>(),
            grad.data_ptr<scalar_t>(),
            sharpness.data_ptr<scalar_t>(),
            smart_grad.data_ptr<scalar_t>(),
            active_mask.data_ptr<bool>(),
            alpha,
            W1_f.data_ptr<float>(),
            b1_f.data_ptr<float>(),
            W2_f.data_ptr<float>(),
            b2_f.data_ptr<float>(),
            rescale,
            N,
            hidden_dim
        );
    }));
}

void launch_fused_sg11_adam_cosine_gate_moe(
    torch::Tensor param,
    torch::Tensor exp_avg,
    torch::Tensor exp_avg_sq,
    torch::Tensor smart_grad,
    torch::Tensor mu,
    torch::Tensor active_mask,
    float lamb_eff,
    float beta1,
    float beta2,
    float lr,
    float wd_eff,
    float eps,
    float bc1,
    float bc2
) {
    const int N = param.numel();
    if (N == 0) return;

    if (param.scalar_type() == at::ScalarType::Float &&
        (N % 4 == 0) &&
        (reinterpret_cast<uintptr_t>(param.data_ptr<float>()) % 16 == 0) &&
        (reinterpret_cast<uintptr_t>(exp_avg.data_ptr<float>()) % 16 == 0) &&
        (reinterpret_cast<uintptr_t>(exp_avg_sq.data_ptr<float>()) % 16 == 0) &&
        (reinterpret_cast<uintptr_t>(smart_grad.data_ptr<float>()) % 16 == 0) &&
        (reinterpret_cast<uintptr_t>(mu.data_ptr<float>()) % 16 == 0))
    {
        const int N4 = N / 4;
        const int grid = (N4 + BLOCK_SIZE - 1) / BLOCK_SIZE;
        fused_sg11_adam_cosine_gate_moe_vec4_kernel<<<grid, BLOCK_SIZE>>>(
            reinterpret_cast<float4*>(param.data_ptr<float>()),
            reinterpret_cast<float4*>(exp_avg.data_ptr<float>()),
            reinterpret_cast<float4*>(exp_avg_sq.data_ptr<float>()),
            reinterpret_cast<const float4*>(smart_grad.data_ptr<float>()),
            reinterpret_cast<const float4*>(mu.data_ptr<float>()),
            active_mask.data_ptr<bool>(),
            lamb_eff, beta1, beta2, lr, wd_eff, eps, bc1, bc2, N4
        );
        return;
    }

    const int grid = (N + BLOCK_SIZE - 1) / BLOCK_SIZE;
    AT_DISPATCH_FLOATING_TYPES_AND2(
        at::ScalarType::Half, at::ScalarType::BFloat16,
        param.scalar_type(), "fused_sg11_adam_cosine_gate_moe", ([&] {
        fused_sg11_adam_cosine_gate_moe_kernel<scalar_t><<<grid, BLOCK_SIZE>>>(
            param.data_ptr<scalar_t>(),
            exp_avg.data_ptr<float>(),
            exp_avg_sq.data_ptr<float>(),
            smart_grad.data_ptr<scalar_t>(),
            mu.data_ptr<scalar_t>(),
            active_mask.data_ptr<bool>(),
            lamb_eff, beta1, beta2, lr, wd_eff, eps, bc1, bc2, N
        );
    }));
}

void launch_fused_neuralgrok_amplifier_moe(
    torch::Tensor grad,
    torch::Tensor amplified_grad,
    torch::Tensor active_mask,
    torch::Tensor W1,
    torch::Tensor b1,
    torch::Tensor W2,
    torch::Tensor b2,
    float alpha,
    float beta,
    int hidden_dim
) {
    const int N = grad.numel();
    if (N == 0) return;
    const int grid = (N + BLOCK_SIZE - 1) / BLOCK_SIZE;
    const int smem_elems = hidden_dim * 3 + 1;
    const int smem_bytes = smem_elems * sizeof(float);

    auto W1_f = W1.to(torch::kFloat32).contiguous();
    auto b1_f = b1.to(torch::kFloat32).contiguous();
    auto W2_f = W2.to(torch::kFloat32).contiguous();
    auto b2_f = b2.to(torch::kFloat32).contiguous();

    AT_DISPATCH_FLOATING_TYPES_AND2(
        at::ScalarType::Half, at::ScalarType::BFloat16,
        grad.scalar_type(), "fused_neuralgrok_amplifier_moe", ([&] {
            fused_neuralgrok_amplifier_moe_kernel<scalar_t><<<grid, BLOCK_SIZE, smem_bytes>>>(
                grad.data_ptr<scalar_t>(),
                amplified_grad.data_ptr<scalar_t>(),
                active_mask.data_ptr<bool>(),
                W1_f.data_ptr<float>(),
                b1_f.data_ptr<float>(),
                W2_f.data_ptr<float>(),
                b2_f.data_ptr<float>(),
                alpha,
                beta,
                N,
                hidden_dim
            );
        })
    );
}

